import 'dart:convert';

Id idFromJson(String str) => Id.fromJson(json.decode(str));

String idToJson(Id data) => json.encode(data.toJson());

class Id {
    String commands;
    String options;
    String examples;
    String boolean;
    String count;
    String number;
    String string;
    String array;
    String required;
    String idDefault;
    String purpleDefault;
    String aliases;
    String choices;
    String generatedValue;
    MissingArgumentValueS notEnoughNonOptionArgumentsGotSNeedAtLeastS;
    MissingArgumentValueS tooManyNonOptionArgumentsGotSMaximumOfS;
    MissingArgumentValueS missingArgumentValueS;
    MissingArgumentValueS missingRequiredArgumentS;
    MissingArgumentValueS unknownArgumentS;
    String invalidValues;
    String argumentSGivenSChoicesS;
    String argumentCheckFailedS;
    String implicationsFailed;
    String notEnoughArgumentsFollowingS;
    String invalidJsonConfigFileS;
    String pathToJsonConfigFile;
    String showHelp;
    String showVersionNumber;
    String didYouMeanS;
    String argumentsSAndSAreMutuallyExclusive;
    String positionals;
    String command;

    Id({
        required this.commands,
        required this.options,
        required this.examples,
        required this.boolean,
        required this.count,
        required this.number,
        required this.string,
        required this.array,
        required this.required,
        required this.idDefault,
        required this.purpleDefault,
        required this.aliases,
        required this.choices,
        required this.generatedValue,
        required this.notEnoughNonOptionArgumentsGotSNeedAtLeastS,
        required this.tooManyNonOptionArgumentsGotSMaximumOfS,
        required this.missingArgumentValueS,
        required this.missingRequiredArgumentS,
        required this.unknownArgumentS,
        required this.invalidValues,
        required this.argumentSGivenSChoicesS,
        required this.argumentCheckFailedS,
        required this.implicationsFailed,
        required this.notEnoughArgumentsFollowingS,
        required this.invalidJsonConfigFileS,
        required this.pathToJsonConfigFile,
        required this.showHelp,
        required this.showVersionNumber,
        required this.didYouMeanS,
        required this.argumentsSAndSAreMutuallyExclusive,
        required this.positionals,
        required this.command,
    });

    factory Id.fromJson(Map<String, dynamic> json) => Id(
        commands: json["Commands:"],
        options: json["Options:"],
        examples: json["Examples:"],
        boolean: json["boolean"],
        count: json["count"],
        number: json["number"],
        string: json["string"],
        array: json["array"],
        required: json["required"],
        idDefault: json["default"],
        purpleDefault: json["default:"],
        aliases: json["aliases:"],
        choices: json["choices:"],
        generatedValue: json["generated-value"],
        notEnoughNonOptionArgumentsGotSNeedAtLeastS: MissingArgumentValueS.fromJson(json["Not enough non-option arguments: got %s, need at least %s"]),
        tooManyNonOptionArgumentsGotSMaximumOfS: MissingArgumentValueS.fromJson(json["Too many non-option arguments: got %s, maximum of %s"]),
        missingArgumentValueS: MissingArgumentValueS.fromJson(json["Missing argument value: %s"]),
        missingRequiredArgumentS: MissingArgumentValueS.fromJson(json["Missing required argument: %s"]),
        unknownArgumentS: MissingArgumentValueS.fromJson(json["Unknown argument: %s"]),
        invalidValues: json["Invalid values:"],
        argumentSGivenSChoicesS: json["Argument: %s, Given: %s, Choices: %s"],
        argumentCheckFailedS: json["Argument check failed: %s"],
        implicationsFailed: json["Implications failed:"],
        notEnoughArgumentsFollowingS: json["Not enough arguments following: %s"],
        invalidJsonConfigFileS: json["Invalid JSON config file: %s"],
        pathToJsonConfigFile: json["Path to JSON config file"],
        showHelp: json["Show help"],
        showVersionNumber: json["Show version number"],
        didYouMeanS: json["Did you mean %s?"],
        argumentsSAndSAreMutuallyExclusive: json["Arguments %s and %s are mutually exclusive"],
        positionals: json["Positionals:"],
        command: json["command"],
    );

    Map<String, dynamic> toJson() => {
        "Commands:": commands,
        "Options:": options,
        "Examples:": examples,
        "boolean": boolean,
        "count": count,
        "number": number,
        "string": string,
        "array": array,
        "required": required,
        "default": idDefault,
        "default:": purpleDefault,
        "aliases:": aliases,
        "choices:": choices,
        "generated-value": generatedValue,
        "Not enough non-option arguments: got %s, need at least %s": notEnoughNonOptionArgumentsGotSNeedAtLeastS.toJson(),
        "Too many non-option arguments: got %s, maximum of %s": tooManyNonOptionArgumentsGotSMaximumOfS.toJson(),
        "Missing argument value: %s": missingArgumentValueS.toJson(),
        "Missing required argument: %s": missingRequiredArgumentS.toJson(),
        "Unknown argument: %s": unknownArgumentS.toJson(),
        "Invalid values:": invalidValues,
        "Argument: %s, Given: %s, Choices: %s": argumentSGivenSChoicesS,
        "Argument check failed: %s": argumentCheckFailedS,
        "Implications failed:": implicationsFailed,
        "Not enough arguments following: %s": notEnoughArgumentsFollowingS,
        "Invalid JSON config file: %s": invalidJsonConfigFileS,
        "Path to JSON config file": pathToJsonConfigFile,
        "Show help": showHelp,
        "Show version number": showVersionNumber,
        "Did you mean %s?": didYouMeanS,
        "Arguments %s and %s are mutually exclusive": argumentsSAndSAreMutuallyExclusive,
        "Positionals:": positionals,
        "command": command,
    };
}

class MissingArgumentValueS {
    String one;
    String other;

    MissingArgumentValueS({
        required this.one,
        required this.other,
    });

    factory MissingArgumentValueS.fromJson(Map<String, dynamic> json) => MissingArgumentValueS(
        one: json["one"],
        other: json["other"],
    );

    Map<String, dynamic> toJson() => {
        "one": one,
        "other": other,
    };
}
